CREATE OR REPLACE FUNCTION fpb_get_loan_int_resign (as_reqno char , as_name char) RETURNS bigint AS $body$
DECLARE

ldc_number  decimal;

BEGIN
  if upper(trim(both as_name)) = 'LON_BAL' then
    select  sum(coalesce(principal_balance,0)) into STRICT ldc_number
    from    sc_mem_m_resign_loan
    where   resign_doc_no = as_reqno;
  elsif  upper(trim(both as_name)) = 'LON_INT' then
    select  sum(coalesce(interest,0) + coalesce(interest_arrear,0)) into STRICT ldc_number
    from    sc_mem_m_resign_loan
    where   resign_doc_no = as_reqno;
  else
    ldc_number := 0;
  end if;

  return ldc_number;

end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
